CREATE TABLE driver_race_history (
  race_id           VARCHAR(50)  NOT NULL,
  gp_name           VARCHAR(50)  NOT NULL,
  race_date         DATE         NOT NULL,
  car_number        INT          NOT NULL,
  driver            VARCHAR(100) NOT NULL,
  team              VARCHAR(100) NOT NULL,
  starting_grid     INT          NOT NULL,
  finishing_pos     INT          NOT NULL,
  positions_gained  INT          NOT NULL,
  pit_stops         INT          NOT NULL CHECK (pit_stops BETWEEN 1 AND 2),
  stint_1_tire      VARCHAR(10)  NOT NULL,
  stint_2_tire      VARCHAR(10)  NOT NULL,
  stint_3_tire      VARCHAR(10)  NOT NULL DEFAULT 'n/a',
  PRIMARY KEY (race_id, car_number)
);

CREATE INDEX idx_driver_race_history_car_number ON driver_race_history(car_number);
CREATE INDEX idx_driver_race_history_driver ON driver_race_history(driver);

